),
"CQMCommon.Inpatient Encounter" AS (
SELECT * FROM "Encounter: Encounter Inpatient" AS EncounterInpatient WHERE EncounterInpatient.status = 'finished' AND CAST(intervalEnd(fhirpath_text(EncounterInpatient.resource, 'period')) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"ED Encounter During MP" AS (
SELECT * FROM "Encounter: Emergency Department Evaluation and Management Visit" AS EDEncounter WHERE CAST(intervalEnd(fhirpath_text(EDEncounter.resource, 'period')) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)) AND EDEncounter.status = 'finished' AND EXTRACT(YEAR FROM CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS DATE)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS DATE)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS DATE)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST(intervalStart(fhirpath_text(EDEncounter.resource, 'period')) AS DATE)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = EDEncounter.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 18
),
"ED Encounter with STEMI Diagnosis" AS (
SELECT * FROM "ED Encounter During MP" AS EDEncounterinMP WHERE in_valueset(EDEncounterinMP.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.3157.4017') OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: STEMI (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: STEMI (qicore-condition-encounter-diagnosis)") AS DxSTEMI WHERE (EXISTS (SELECT 1 FROM (SELECT unnest((SELECT list(CASE WHEN (SELECT COUNT(*) FROM (SELECT patient_id, resource FROM "Condition (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition (qicore-condition-problems-health-concerns)") AS C WHERE fhirpath_text(C.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_D, 'reference'), '/'), -1) AND C.patient_id = EDEncounterinMP.patient_id) = 1 THEN (SELECT resource FROM (SELECT patient_id, resource FROM "Condition (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition (qicore-condition-problems-health-concerns)") AS C WHERE fhirpath_text(C.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_D, 'reference'), '/'), -1) AND C.patient_id = EDEncounterinMP.patient_id LIMIT 1) ELSE NULL END) FROM (SELECT unnest(from_json(fhirpath(EDEncounterinMP.resource, 'reasonReference'), '["VARCHAR"]')) AS _lt_D) AS _lt_unnest)) AS _ivr) AS _ivt WHERE in_valueset(_ivr, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.3157.4017')) OR intervalContains(fhirpath_text(EDEncounterinMP.resource, 'period'), intervalStart(CASE WHEN fhirpath_text(DxSTEMI.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(DxSTEMI.resource, 'onsetDateTime'), fhirpath_text(DxSTEMI.resource, 'onsetPeriod.start'), fhirpath_text(DxSTEMI.resource, 'recordedDate')), fhirpath_text(DxSTEMI.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(DxSTEMI.resource, 'onsetDateTime'), fhirpath_text(DxSTEMI.resource, 'onsetPeriod.start'), fhirpath_text(DxSTEMI.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(DxSTEMI.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(DxSTEMI.resource, 'onsetDateTime'), fhirpath_text(DxSTEMI.resource, 'onsetPeriod.start'), fhirpath_text(DxSTEMI.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(DxSTEMI.resource, 'onsetDateTime'), fhirpath_text(DxSTEMI.resource, 'onsetPeriod.start'), fhirpath_text(DxSTEMI.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END))) AND (NOT (fhirpath_text(DxSTEMI.resource, 'verificationStatus') IS NOT NULL) OR fhirpath_bool(DxSTEMI.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') OR fhirpath_bool(DxSTEMI.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''unconfirmed'').exists()') OR fhirpath_bool(DxSTEMI.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''provisional'').exists()') OR fhirpath_bool(DxSTEMI.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''differential'').exists()')) AND DxSTEMI.patient_id = EDEncounterinMP.patient_id)
),
"Active Exclusion Diagnosis Within 90 Days Before or At the Start of ED Encounter" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwSTEMI WHERE EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "Condition: Ischemic Stroke (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Closed Head and Facial Trauma (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Active Peptic Ulcer (qicore-condition-problems-health-concerns)") AS ExclusionCondition WHERE intervalContains(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), '{"value": 90.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), TRUE, TRUE), intervalStart(CASE WHEN fhirpath_text(ExclusionCondition.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ExclusionCondition.resource, 'onsetDateTime'), fhirpath_text(ExclusionCondition.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionCondition.resource, 'recordedDate')), fhirpath_text(ExclusionCondition.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ExclusionCondition.resource, 'onsetDateTime'), fhirpath_text(ExclusionCondition.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionCondition.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ExclusionCondition.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ExclusionCondition.resource, 'onsetDateTime'), fhirpath_text(ExclusionCondition.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionCondition.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ExclusionCondition.resource, 'onsetDateTime'), fhirpath_text(ExclusionCondition.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionCondition.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) AND (NOT (fhirpath_text(ExclusionCondition.resource, 'verificationStatus') IS NOT NULL) OR fhirpath_bool(ExclusionCondition.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') OR fhirpath_bool(ExclusionCondition.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''unconfirmed'').exists()') OR fhirpath_bool(ExclusionCondition.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''provisional'').exists()') OR fhirpath_bool(ExclusionCondition.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''differential'').exists()')) AND ExclusionCondition.patient_id = EDwSTEMI.patient_id)
),
"Active Exclusion Diagnosis at Start of ED Encounter" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "Condition: Active Bleeding or Bleeding Diathesis, Excluding Menses (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Malignant Intracranial Neoplasm Group (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Cerebral Vascular Lesion (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Dementia and Related Intracranial Pathologies (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Pregnant State (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Allergy to thrombolytics (qicore-condition-problems-health-concerns)") AS ActiveExclusionDx WHERE intervalOverlapsBefore(CASE WHEN fhirpath_text(ActiveExclusionDx.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ActiveExclusionDx.resource, 'onsetDateTime'), fhirpath_text(ActiveExclusionDx.resource, 'onsetPeriod.start'), fhirpath_text(ActiveExclusionDx.resource, 'recordedDate')), fhirpath_text(ActiveExclusionDx.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ActiveExclusionDx.resource, 'onsetDateTime'), fhirpath_text(ActiveExclusionDx.resource, 'onsetPeriod.start'), fhirpath_text(ActiveExclusionDx.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ActiveExclusionDx.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ActiveExclusionDx.resource, 'onsetDateTime'), fhirpath_text(ActiveExclusionDx.resource, 'onsetPeriod.start'), fhirpath_text(ActiveExclusionDx.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ActiveExclusionDx.resource, 'onsetDateTime'), fhirpath_text(ActiveExclusionDx.resource, 'onsetPeriod.start'), fhirpath_text(ActiveExclusionDx.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, fhirpath_text(EDwithSTEMI.resource, 'period')) AND (NOT (fhirpath_text(ActiveExclusionDx.resource, 'verificationStatus') IS NOT NULL) OR fhirpath_bool(ActiveExclusionDx.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') OR fhirpath_bool(ActiveExclusionDx.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''unconfirmed'').exists()') OR fhirpath_bool(ActiveExclusionDx.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''provisional'').exists()') OR fhirpath_bool(ActiveExclusionDx.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''differential'').exists()')) AND ActiveExclusionDx.patient_id = EDwithSTEMI.patient_id)
),
"Active Long Term use of Anticoagulants" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE EXISTS (SELECT 1 FROM "Condition: Long term (current) use of anticoagulants (qicore-condition-problems-health-concerns)" AS LongTermAnticoagulant WHERE intervalStart(CASE WHEN fhirpath_text(LongTermAnticoagulant.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(LongTermAnticoagulant.resource, 'onsetDateTime'), fhirpath_text(LongTermAnticoagulant.resource, 'onsetPeriod.start'), fhirpath_text(LongTermAnticoagulant.resource, 'recordedDate')), fhirpath_text(LongTermAnticoagulant.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(LongTermAnticoagulant.resource, 'onsetDateTime'), fhirpath_text(LongTermAnticoagulant.resource, 'onsetPeriod.start'), fhirpath_text(LongTermAnticoagulant.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(LongTermAnticoagulant.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(LongTermAnticoagulant.resource, 'onsetDateTime'), fhirpath_text(LongTermAnticoagulant.resource, 'onsetPeriod.start'), fhirpath_text(LongTermAnticoagulant.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(LongTermAnticoagulant.resource, 'onsetDateTime'), fhirpath_text(LongTermAnticoagulant.resource, 'onsetPeriod.start'), fhirpath_text(LongTermAnticoagulant.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) <= intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AND CAST(intervalEnd(CASE WHEN fhirpath_text(LongTermAnticoagulant.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(LongTermAnticoagulant.resource, 'onsetDateTime'), fhirpath_text(LongTermAnticoagulant.resource, 'onsetPeriod.start'), fhirpath_text(LongTermAnticoagulant.resource, 'recordedDate')), fhirpath_text(LongTermAnticoagulant.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(LongTermAnticoagulant.resource, 'onsetDateTime'), fhirpath_text(LongTermAnticoagulant.resource, 'onsetPeriod.start'), fhirpath_text(LongTermAnticoagulant.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(LongTermAnticoagulant.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(LongTermAnticoagulant.resource, 'onsetDateTime'), fhirpath_text(LongTermAnticoagulant.resource, 'onsetPeriod.start'), fhirpath_text(LongTermAnticoagulant.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(LongTermAnticoagulant.resource, 'onsetDateTime'), fhirpath_text(LongTermAnticoagulant.resource, 'onsetPeriod.start'), fhirpath_text(LongTermAnticoagulant.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) >= CAST(intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AS DATE) AND (NOT (fhirpath_text(LongTermAnticoagulant.resource, 'verificationStatus') IS NOT NULL) OR fhirpath_bool(LongTermAnticoagulant.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') OR fhirpath_bool(LongTermAnticoagulant.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''unconfirmed'').exists()') OR fhirpath_bool(LongTermAnticoagulant.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''provisional'').exists()') OR fhirpath_bool(LongTermAnticoagulant.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''differential'').exists()')) AND LongTermAnticoagulant.patient_id = EDwithSTEMI.patient_id)
),
"Active Oral Anticoagulant Medication at the Start of ED Encounter" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE EXISTS (SELECT 1 FROM "MedicationRequest: Oral Anticoagulant Medications" AS OralAnticoagulant WHERE array_contains(['active', 'completed'], fhirpath_text(OralAnticoagulant.resource, 'status')) AND fhirpath_text(OralAnticoagulant.resource, 'intent') = 'order' AND CAST(intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AS TIMESTAMP) - INTERVAL '90 day' <= CAST(fhirpath_text(OralAnticoagulant.resource, 'authoredOn') AS TIMESTAMP) AND CAST(fhirpath_text(OralAnticoagulant.resource, 'authoredOn') AS TIMESTAMP) <= CAST(intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AS TIMESTAMP) AND OralAnticoagulant.patient_id = EDwithSTEMI.patient_id)
),
"Active use of Anticoagulants" AS (
(SELECT patient_id, resource FROM "Active Oral Anticoagulant Medication at the Start of ED Encounter") UNION (SELECT patient_id, resource FROM "Active Long Term use of Anticoagulants")
),
"Adverse Effect to Thrombolytic Medications Before End of ED Encounter" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwSTEMI WHERE EXISTS (SELECT 1 FROM "AdverseEvent: Thrombolytics Adverse Event" AS ThrombolyticAdverseEvent WHERE CAST(COALESCE(fhirpath_text(ThrombolyticAdverseEvent.resource, 'date'), fhirpath_text(ThrombolyticAdverseEvent.resource, 'detected'), fhirpath_text(ThrombolyticAdverseEvent.resource, 'recordedDate')) AS TIMESTAMP) < CAST(intervalEnd(fhirpath_text(EDwSTEMI.resource, 'period')) AS TIMESTAMP) AND fhirpath_text(ThrombolyticAdverseEvent.resource, 'actuality') = 'actual' AND ThrombolyticAdverseEvent.patient_id = EDwSTEMI.patient_id)
),
"Allergy or Intolerance to Thrombolytic Medications Overlaps ED Encounter" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwSTEMI WHERE EXISTS (SELECT 1 FROM "AllergyIntolerance: Thrombolytic medications" AS ThrombolyticAllergy WHERE fhirpath_bool(ThrombolyticAllergy.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/allergyintolerance-clinical'' and code=''active'').exists()') AND (NOT (fhirpath_text(ThrombolyticAllergy.resource, 'verificationStatus') IS NOT NULL) OR fhirpath_bool(ThrombolyticAllergy.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/allergyintolerance-verification'' and code=''confirmed'').exists()') OR fhirpath_bool(ThrombolyticAllergy.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/allergyintolerance-verification'' and code=''unconfirmed'').exists()')) AND intervalOverlaps(CASE WHEN fhirpath_text(ThrombolyticAllergy.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ThrombolyticAllergy.resource, 'onset')), '{') THEN fhirpath_text(ThrombolyticAllergy.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(ThrombolyticAllergy.resource, 'onset'), fhirpath_text(ThrombolyticAllergy.resource, 'onset'), TRUE, TRUE) END, fhirpath_text(EDwSTEMI.resource, 'period')) AND ThrombolyticAllergy.patient_id = EDwSTEMI.patient_id)
),
"Currently Pregnant" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwSTEMI WHERE EXISTS (SELECT 1 FROM "Observation" AS PregStatus WHERE fhirpath_text(PregStatus.resource, 'status') = 'final' AND in_valueset(PregStatus.resource, 'value', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.3157.4055') AND intervalOverlaps(CASE WHEN fhirpath_text(PregStatus.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PregStatus.resource, 'effective')), '{') THEN fhirpath_text(PregStatus.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(PregStatus.resource, 'effective'), fhirpath_text(PregStatus.resource, 'effective'), TRUE, TRUE) END, fhirpath_text(EDwSTEMI.resource, 'period')) AND PregStatus.patient_id = EDwSTEMI.patient_id)
),
"ED Departure with Discharge to Acute Care Facility Within 45 Minutes Of Arrival" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE CAST(list_extract(list_sort((SELECT list(intervalStart(fhirpath_text(_lt_EDLocation, 'period'))) FROM (SELECT unnest(from_json(fhirpath(EDwithSTEMI.resource, 'location'), '["VARCHAR"]')) AS _lt_EDLocation) AS _lt_unnest WHERE (in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.292') OR fhirpath_bool(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id LIMIT 1) ELSE NULL END, 'type.coding.where(system=''http://terminology.hl7.org/CodeSystem/v3-RoleCode'' and code=''ER'').exists()')) AND intervalStart(fhirpath_text(_lt_EDLocation, 'period')) IS NOT NULL), 'asc'), 1) AS TIMESTAMP) < CAST(list_extract(list_sort((SELECT list(intervalEnd(fhirpath_text(_lt_EDLocation, 'period'))) FROM (SELECT unnest(from_json(fhirpath(EDwithSTEMI.resource, 'location'), '["VARCHAR"]')) AS _lt_EDLocation) AS _lt_unnest WHERE (in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.292') OR fhirpath_bool(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id LIMIT 1) ELSE NULL END, 'type.coding.where(system=''http://terminology.hl7.org/CodeSystem/v3-RoleCode'' and code=''ER'').exists()')) AND intervalEnd(fhirpath_text(_lt_EDLocation, 'period')) IS NOT NULL), 'asc'), -1) AS TIMESTAMP) AND CAST(list_extract(list_sort((SELECT list(intervalEnd(fhirpath_text(_lt_EDLocation, 'period'))) FROM (SELECT unnest(from_json(fhirpath(EDwithSTEMI.resource, 'location'), '["VARCHAR"]')) AS _lt_EDLocation) AS _lt_unnest WHERE (in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.292') OR fhirpath_bool(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id LIMIT 1) ELSE NULL END, 'type.coding.where(system=''http://terminology.hl7.org/CodeSystem/v3-RoleCode'' and code=''ER'').exists()')) AND intervalEnd(fhirpath_text(_lt_EDLocation, 'period')) IS NOT NULL), 'asc'), -1) AS TIMESTAMP) <= CAST(list_extract(list_sort((SELECT list(intervalStart(fhirpath_text(_lt_EDLocation, 'period'))) FROM (SELECT unnest(from_json(fhirpath(EDwithSTEMI.resource, 'location'), '["VARCHAR"]')) AS _lt_EDLocation) AS _lt_unnest WHERE (in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.292') OR fhirpath_bool(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = EDwithSTEMI.patient_id LIMIT 1) ELSE NULL END, 'type.coding.where(system=''http://terminology.hl7.org/CodeSystem/v3-RoleCode'' and code=''ER'').exists()')) AND intervalStart(fhirpath_text(_lt_EDLocation, 'period')) IS NOT NULL), 'asc'), 1) AS TIMESTAMP) + INTERVAL '45 minute' AND in_valueset(EDwithSTEMI.resource, 'hospitalization.dischargeDisposition', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.87')
),
"ED Encounter with Discharge Disposition as Left Against Medical Advice" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwSTEMI WHERE in_valueset(EDwSTEMI.resource, 'hospitalization.dischargeDisposition', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.308')
),
"ED Encounter with Discharge Disposition as Patient Expired" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE in_valueset(EDwithSTEMI.resource, 'hospitalization.dischargeDisposition', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.309')
),
"ED Encounter with Hospice Services" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwSTEMI WHERE EXISTS (SELECT * FROM "Encounter: Encounter Inpatient" AS InpatientEncounter WHERE (fhirpath_bool(InpatientEncounter.resource, 'hospitalization.dischargeDisposition.coding.where(system=''http://snomed.info/sct'' and code=''428361000124107'').exists()') OR fhirpath_bool(InpatientEncounter.resource, 'hospitalization.dischargeDisposition.coding.where(system=''http://snomed.info/sct'' and code=''428371000124100'').exists()')) AND fhirpath_text(InpatientEncounter.resource, 'status') = 'finished' AND intervalStart(fhirpath_text(InpatientEncounter.resource, 'period')) <= intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AND CAST(intervalStart(fhirpath_text(InpatientEncounter.resource, 'period')) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), '{"value": 6.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(intervalEnd(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(fhirpath_text(InpatientEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), '{"value": 6.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(intervalEnd(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), TRUE, TRUE)) AS DATE) AND InpatientEncounter.patient_id = EDwSTEMI.patient_id) OR EXISTS (SELECT * FROM "Encounter: Hospice Encounter" AS HospiceEncounter WHERE intervalStart(fhirpath_text(HospiceEncounter.resource, 'period')) <= intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AND CAST(intervalStart(fhirpath_text(HospiceEncounter.resource, 'period')) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), '{"value": 6.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(intervalEnd(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(fhirpath_text(HospiceEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), '{"value": 6.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(intervalEnd(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), TRUE, TRUE)) AS DATE) AND fhirpath_text(HospiceEncounter.resource, 'status') = 'finished' AND HospiceEncounter.patient_id = EDwSTEMI.patient_id) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Observation: Hospice care [Minimum Data Set]" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS HospiceAssessment WHERE fhirpath_bool(HospiceAssessment.resource, 'value.coding.where(system=''http://snomed.info/sct'' and code=''373066001'').exists()') AND intervalStart(CASE WHEN fhirpath_text(HospiceAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospiceAssessment.resource, 'effective')), '{') THEN fhirpath_text(HospiceAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HospiceAssessment.resource, 'effective'), fhirpath_text(HospiceAssessment.resource, 'effective'), TRUE, TRUE) END) <= intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AND CAST(intervalStart(CASE WHEN fhirpath_text(HospiceAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospiceAssessment.resource, 'effective')), '{') THEN fhirpath_text(HospiceAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HospiceAssessment.resource, 'effective'), fhirpath_text(HospiceAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), '{"value": 6.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(intervalEnd(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospiceAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospiceAssessment.resource, 'effective')), '{') THEN fhirpath_text(HospiceAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HospiceAssessment.resource, 'effective'), fhirpath_text(HospiceAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), '{"value": 6.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(intervalEnd(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), TRUE, TRUE)) AS DATE) AND HospiceAssessment.patient_id = EDwSTEMI.patient_id) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "ServiceRequest: Hospice Care Ambulatory" WHERE fhirpath_text(resource, 'status') IN ('active', 'completed') AND fhirpath_text(resource, 'intent') IN ('order', 'original-order', 'reflex-order', 'filler-order', 'instance-order')) AS HospiceOrder WHERE CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS TIMESTAMP) - INTERVAL '6 month' <= CAST(fhirpath_text(HospiceOrder.resource, 'authoredOn') AS TIMESTAMP) AND CAST(fhirpath_text(HospiceOrder.resource, 'authoredOn') AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS TIMESTAMP) AND HospiceOrder.patient_id = EDwSTEMI.patient_id) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Hospice Care Ambulatory" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS HospicePerformed WHERE intervalStart(CASE WHEN fhirpath_text(HospicePerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospicePerformed.resource, 'performed')), '{') THEN fhirpath_text(HospicePerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HospicePerformed.resource, 'performed'), fhirpath_text(HospicePerformed.resource, 'performed'), TRUE, TRUE) END) <= intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AND CAST(intervalStart(CASE WHEN fhirpath_text(HospicePerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospicePerformed.resource, 'performed')), '{') THEN fhirpath_text(HospicePerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HospicePerformed.resource, 'performed'), fhirpath_text(HospicePerformed.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), '{"value": 6.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(intervalEnd(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospicePerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospicePerformed.resource, 'performed')), '{') THEN fhirpath_text(HospicePerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HospicePerformed.resource, 'performed'), fhirpath_text(HospicePerformed.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), '{"value": 6.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(intervalEnd(fhirpath_text(EDwSTEMI.resource, 'period')) AS VARCHAR), TRUE, TRUE)) AS DATE) AND HospicePerformed.patient_id = EDwSTEMI.patient_id) OR EXISTS (SELECT * FROM "Condition: Hospice Diagnosis (qicore-condition-problems-health-concerns)" AS HospiceCareDiagnosis WHERE CAST(intervalEnd(CASE WHEN fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HospiceCareDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) >= CAST(intervalStart(fhirpath_text(EDwSTEMI.resource, 'period')) AS DATE) AND (NOT (fhirpath_text(HospiceCareDiagnosis.resource, 'verificationStatus') IS NOT NULL) OR fhirpath_bool(HospiceCareDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') OR fhirpath_bool(HospiceCareDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''unconfirmed'').exists()') OR fhirpath_bool(HospiceCareDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''provisional'').exists()') OR fhirpath_bool(HospiceCareDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''differential'').exists()')) AND HospiceCareDiagnosis.patient_id = EDwSTEMI.patient_id)
),
"ED Encounter with a Documented Reason for No PCI Performed" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwSTEMI WHERE EXISTS (SELECT 1 FROM "Procedure: Percutaneous Coronary Intervention (procedurenotdone)" AS PCINotDone WHERE (in_valueset(PCINotDone.resource, 'statusReason', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.93') OR in_valueset(PCINotDone.resource, 'statusReason', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1282.2')) AND intervalContains(fhirpath_text(EDwSTEMI.resource, 'period'), fhirpath_text(PCINotDone.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-recorded'').valueDateTime')) AND PCINotDone.patient_id = EDwSTEMI.patient_id)
),
"ED Encounter with a Documented Reason for Not Administering Fibrinolytic Therapy" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwSTEMI WHERE EXISTS (SELECT 1 FROM "MedicationAdministration: Fibrinolytic Therapy (medicationadministrationnotdone)" AS FibrinolyticNoMed WHERE (in_valueset(FibrinolyticNoMed.resource, 'statusReason', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.93') OR in_valueset(FibrinolyticNoMed.resource, 'statusReason', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1282.1')) AND intervalContains(fhirpath_text(EDwSTEMI.resource, 'period'), fhirpath_text(FibrinolyticNoMed.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-recorded'').valueDateTime')) AND FibrinolyticNoMed.patient_id = EDwSTEMI.patient_id)
),
"Exclusion Diagnosis During ED Encounter or Within 24 Hours of ED Encounter Start" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "Condition: Aortic Dissection or Ruptured Aortic Aneurysm (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Neurologic impairment (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Angina pectoris with documented spasm (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Ventricular aneurysm due to and following acute myocardial infarction (disorder) (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Aneurysm of heart (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Takotsubo cardiomyopathy (disorder) (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Takotsubo syndrome (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Cardiopulmonary Emergency (qicore-condition-problems-health-concerns)") AS ExclusionDiagnosis WHERE (intervalContains(fhirpath_text(EDwithSTEMI.resource, 'period'), intervalStart(CASE WHEN fhirpath_text(ExclusionDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), fhirpath_text(ExclusionDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ExclusionDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) OR CAST(intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AS TIMESTAMP) - INTERVAL '24 hour' <= CAST(intervalStart(CASE WHEN fhirpath_text(ExclusionDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), fhirpath_text(ExclusionDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ExclusionDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS TIMESTAMP) AND CAST(intervalStart(CASE WHEN fhirpath_text(ExclusionDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), fhirpath_text(ExclusionDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ExclusionDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ExclusionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(ExclusionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(ExclusionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AS TIMESTAMP)) AND (NOT (fhirpath_text(ExclusionDiagnosis.resource, 'verificationStatus') IS NOT NULL) OR fhirpath_bool(ExclusionDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') OR fhirpath_bool(ExclusionDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''unconfirmed'').exists()') OR fhirpath_bool(ExclusionDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''provisional'').exists()') OR fhirpath_bool(ExclusionDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''differential'').exists()')) AND ExclusionDiagnosis.patient_id = EDwithSTEMI.patient_id)
),
"Fibrinolytic Therapy Administration within 30 Minutes of Arrival" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE EXISTS (SELECT 1 FROM "MedicationAdministration: Fibrinolytic Therapy" AS Fibrinolytic WHERE fhirpath_text(Fibrinolytic.resource, 'status') = 'completed' AND CAST(list_extract(list_sort((SELECT list(intervalStart(fhirpath_text(_lt_EDLocation, 'period'))) FROM (SELECT unnest(from_json(fhirpath(EDwithSTEMI.resource, 'location'), '["VARCHAR"]')) AS _lt_EDLocation) AS _lt_unnest WHERE (in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = Fibrinolytic.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = Fibrinolytic.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.292') OR fhirpath_bool(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = Fibrinolytic.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = Fibrinolytic.patient_id LIMIT 1) ELSE NULL END, 'type.coding.where(system=''http://terminology.hl7.org/CodeSystem/v3-RoleCode'' and code=''ER'').exists()')) AND intervalStart(fhirpath_text(_lt_EDLocation, 'period')) IS NOT NULL), 'asc'), 1) AS TIMESTAMP) < CAST(intervalStart(CASE WHEN fhirpath_text(Fibrinolytic.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(Fibrinolytic.resource, 'effective')), '{') THEN fhirpath_text(Fibrinolytic.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(Fibrinolytic.resource, 'effective'), fhirpath_text(Fibrinolytic.resource, 'effective'), TRUE, TRUE) END) AS TIMESTAMP) AND CAST(intervalStart(CASE WHEN fhirpath_text(Fibrinolytic.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(Fibrinolytic.resource, 'effective')), '{') THEN fhirpath_text(Fibrinolytic.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(Fibrinolytic.resource, 'effective'), fhirpath_text(Fibrinolytic.resource, 'effective'), TRUE, TRUE) END) AS TIMESTAMP) <= CAST(list_extract(list_sort((SELECT list(intervalStart(fhirpath_text(_lt_EDLocation, 'period'))) FROM (SELECT unnest(from_json(fhirpath(EDwithSTEMI.resource, 'location'), '["VARCHAR"]')) AS _lt_EDLocation) AS _lt_unnest WHERE (in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = Fibrinolytic.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = Fibrinolytic.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.292') OR fhirpath_bool(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = Fibrinolytic.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = Fibrinolytic.patient_id LIMIT 1) ELSE NULL END, 'type.coding.where(system=''http://terminology.hl7.org/CodeSystem/v3-RoleCode'' and code=''ER'').exists()')) AND intervalStart(fhirpath_text(_lt_EDLocation, 'period')) IS NOT NULL), 'asc'), 1) AS TIMESTAMP) + INTERVAL '30 minute' AND Fibrinolytic.patient_id = EDwithSTEMI.patient_id)
),
"Initial Population" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis"
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"Intracranial or Intraspinal Procedure 90 Days or Less Before Start of ED Encounter" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE EXISTS (SELECT 1 FROM "Procedure: Intracranial or Intraspinal surgery" AS CranialorSpinalSurgery WHERE CAST(intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AS TIMESTAMP) - INTERVAL '90 day' <= CAST(intervalStart(CASE WHEN fhirpath_text(CranialorSpinalSurgery.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(CranialorSpinalSurgery.resource, 'performed')), '{') THEN fhirpath_text(CranialorSpinalSurgery.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(CranialorSpinalSurgery.resource, 'performed'), fhirpath_text(CranialorSpinalSurgery.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) AND CAST(intervalStart(CASE WHEN fhirpath_text(CranialorSpinalSurgery.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(CranialorSpinalSurgery.resource, 'performed')), '{') THEN fhirpath_text(CranialorSpinalSurgery.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(CranialorSpinalSurgery.resource, 'performed'), fhirpath_text(CranialorSpinalSurgery.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AS TIMESTAMP) AND fhirpath_text(CranialorSpinalSurgery.resource, 'status') = 'completed' AND CranialorSpinalSurgery.patient_id = EDwithSTEMI.patient_id)
),
"Intubation or Mechanical Circulatory Assist Device Placement or Removal Procedure During ED Encounter or Within 24 Hours of ED Encounter Start" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "Procedure: Endotracheal Intubation" UNION SELECT patient_id, resource FROM "Procedure: Mechanical Circulatory Assist Device") AS AirwayProcedure WHERE (intervalContains(fhirpath_text(EDwithSTEMI.resource, 'period'), intervalStart(CASE WHEN fhirpath_text(AirwayProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AirwayProcedure.resource, 'performed')), '{') THEN fhirpath_text(AirwayProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AirwayProcedure.resource, 'performed'), fhirpath_text(AirwayProcedure.resource, 'performed'), TRUE, TRUE) END)) OR CAST(intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AS TIMESTAMP) - INTERVAL '24 hour' <= CAST(intervalStart(CASE WHEN fhirpath_text(AirwayProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AirwayProcedure.resource, 'performed')), '{') THEN fhirpath_text(AirwayProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AirwayProcedure.resource, 'performed'), fhirpath_text(AirwayProcedure.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) AND CAST(intervalStart(CASE WHEN fhirpath_text(AirwayProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(AirwayProcedure.resource, 'performed')), '{') THEN fhirpath_text(AirwayProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(AirwayProcedure.resource, 'performed'), fhirpath_text(AirwayProcedure.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AS TIMESTAMP)) AND fhirpath_text(AirwayProcedure.resource, 'status') = 'completed' AND AirwayProcedure.patient_id = EDwithSTEMI.patient_id)
),
"Major Surgical Procedure 21 Days or Less Before Start of or Starts During ED Encounter" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE EXISTS (SELECT 1 FROM "Procedure: Major Surgical Procedure" AS MajorSurgery WHERE (CAST(intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AS TIMESTAMP) - INTERVAL '21 day' <= CAST(intervalStart(CASE WHEN fhirpath_text(MajorSurgery.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MajorSurgery.resource, 'performed')), '{') THEN fhirpath_text(MajorSurgery.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(MajorSurgery.resource, 'performed'), fhirpath_text(MajorSurgery.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) AND CAST(intervalStart(CASE WHEN fhirpath_text(MajorSurgery.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MajorSurgery.resource, 'performed')), '{') THEN fhirpath_text(MajorSurgery.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(MajorSurgery.resource, 'performed'), fhirpath_text(MajorSurgery.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) < CAST(intervalStart(fhirpath_text(EDwithSTEMI.resource, 'period')) AS TIMESTAMP) OR intervalContains(fhirpath_text(EDwithSTEMI.resource, 'period'), intervalStart(CASE WHEN fhirpath_text(MajorSurgery.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MajorSurgery.resource, 'performed')), '{') THEN fhirpath_text(MajorSurgery.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(MajorSurgery.resource, 'performed'), fhirpath_text(MajorSurgery.resource, 'performed'), TRUE, TRUE) END))) AND fhirpath_text(MajorSurgery.resource, 'status') = 'completed' AND MajorSurgery.patient_id = EDwithSTEMI.patient_id)
),
"Denominator Exclusions" AS (
(SELECT patient_id, resource FROM "Allergy or Intolerance to Thrombolytic Medications Overlaps ED Encounter") UNION (SELECT patient_id, resource FROM "Adverse Effect to Thrombolytic Medications Before End of ED Encounter") UNION (SELECT patient_id, resource FROM "Active Exclusion Diagnosis at Start of ED Encounter") UNION (SELECT patient_id, resource FROM "Active use of Anticoagulants") UNION (SELECT patient_id, resource FROM "Exclusion Diagnosis During ED Encounter or Within 24 Hours of ED Encounter Start") UNION (SELECT patient_id, resource FROM "Major Surgical Procedure 21 Days or Less Before Start of or Starts During ED Encounter") UNION (SELECT patient_id, resource FROM "Intubation or Mechanical Circulatory Assist Device Placement or Removal Procedure During ED Encounter or Within 24 Hours of ED Encounter Start") UNION (SELECT patient_id, resource FROM "Active Exclusion Diagnosis Within 90 Days Before or At the Start of ED Encounter") UNION (SELECT patient_id, resource FROM "Intracranial or Intraspinal Procedure 90 Days or Less Before Start of ED Encounter") UNION (SELECT patient_id, resource FROM "ED Encounter with Discharge Disposition as Patient Expired") UNION (SELECT patient_id, resource FROM "ED Encounter with Discharge Disposition as Left Against Medical Advice") UNION (SELECT patient_id, resource FROM "ED Encounter with Hospice Services") UNION (SELECT patient_id, resource FROM "Currently Pregnant")
),
"PCI within 90 Minutes of Arrival" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE EXISTS (SELECT 1 FROM "Procedure: Percutaneous Coronary Intervention" AS PCI WHERE CAST(list_extract(list_sort((SELECT list(intervalStart(fhirpath_text(_lt_EDLocation, 'period'))) FROM (SELECT unnest(from_json(fhirpath(EDwithSTEMI.resource, 'location'), '["VARCHAR"]')) AS _lt_EDLocation) AS _lt_unnest WHERE (in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = PCI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = PCI.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.292') OR fhirpath_bool(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = PCI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = PCI.patient_id LIMIT 1) ELSE NULL END, 'type.coding.where(system=''http://terminology.hl7.org/CodeSystem/v3-RoleCode'' and code=''ER'').exists()')) AND intervalStart(fhirpath_text(_lt_EDLocation, 'period')) IS NOT NULL), 'asc'), 1) AS TIMESTAMP) < CAST(intervalStart(CASE WHEN fhirpath_text(PCI.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PCI.resource, 'performed')), '{') THEN fhirpath_text(PCI.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(PCI.resource, 'performed'), fhirpath_text(PCI.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) AND CAST(intervalStart(CASE WHEN fhirpath_text(PCI.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PCI.resource, 'performed')), '{') THEN fhirpath_text(PCI.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(PCI.resource, 'performed'), fhirpath_text(PCI.resource, 'performed'), TRUE, TRUE) END) AS TIMESTAMP) <= CAST(list_extract(list_sort((SELECT list(intervalStart(fhirpath_text(_lt_EDLocation, 'period'))) FROM (SELECT unnest(from_json(fhirpath(EDwithSTEMI.resource, 'location'), '["VARCHAR"]')) AS _lt_EDLocation) AS _lt_unnest WHERE (in_valueset(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = PCI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = PCI.patient_id LIMIT 1) ELSE NULL END, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.292') OR fhirpath_bool(CASE WHEN (SELECT COUNT(*) FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = PCI.patient_id) = 1 THEN (SELECT resource FROM "Location" AS L WHERE fhirpath_text(L.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(_lt_EDLocation, 'location.reference'), '/'), -1) AND L.patient_id = PCI.patient_id LIMIT 1) ELSE NULL END, 'type.coding.where(system=''http://terminology.hl7.org/CodeSystem/v3-RoleCode'' and code=''ER'').exists()')) AND intervalStart(fhirpath_text(_lt_EDLocation, 'period')) IS NOT NULL), 'asc'), 1) AS TIMESTAMP) + INTERVAL '90 minute' AND fhirpath_text(PCI.resource, 'status') = 'completed' AND PCI.patient_id = EDwithSTEMI.patient_id)
),
"Numerator" AS (
(SELECT patient_id, resource FROM "Fibrinolytic Therapy Administration within 30 Minutes of Arrival") UNION (SELECT patient_id, resource FROM "PCI within 90 Minutes of Arrival") UNION (SELECT patient_id, resource FROM "ED Departure with Discharge to Acute Care Facility Within 45 Minutes Of Arrival")
),
"Received tPA in Another Facility within 24 hours Prior to Admission" AS (
SELECT * FROM "ED Encounter with STEMI Diagnosis" AS EDwithSTEMI WHERE EXISTS (SELECT 1 FROM "Condition: Status post administration of tPA (rtPA) in a different facility within the last 24 hours prior to admission to current facility (qicore-condition-problems-health-concerns)" AS TPA WHERE intervalContains(fhirpath_text(EDwithSTEMI.resource, 'period'), intervalStart(CASE WHEN fhirpath_text(TPA.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(TPA.resource, 'onsetDateTime'), fhirpath_text(TPA.resource, 'onsetPeriod.start'), fhirpath_text(TPA.resource, 'recordedDate')), fhirpath_text(TPA.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(TPA.resource, 'onsetDateTime'), fhirpath_text(TPA.resource, 'onsetPeriod.start'), fhirpath_text(TPA.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(TPA.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(TPA.resource, 'onsetDateTime'), fhirpath_text(TPA.resource, 'onsetPeriod.start'), fhirpath_text(TPA.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(TPA.resource, 'onsetDateTime'), fhirpath_text(TPA.resource, 'onsetPeriod.start'), fhirpath_text(TPA.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) AND (NOT (fhirpath_text(TPA.resource, 'verificationStatus') IS NOT NULL) OR fhirpath_bool(TPA.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') OR fhirpath_bool(TPA.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''unconfirmed'').exists()') OR fhirpath_bool(TPA.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''provisional'').exists()') OR fhirpath_bool(TPA.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''differential'').exists()')) AND TPA.patient_id = EDwithSTEMI.patient_id)
),
"Denominator Exceptions" AS (
(SELECT patient_id, resource FROM "Received tPA in Another Facility within 24 hours Prior to Admission") UNION (SELECT patient_id, resource FROM "ED Encounter with a Documented Reason for No PCI Performed") UNION (SELECT patient_id, resource FROM "ED Encounter with a Documented Reason for Not Administering Fibrinolytic Therapy")
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT COALESCE(LIST(json_extract_string("Initial Population".resource, '$.resourceType') || '/' || json_extract_string("Initial Population".resource, '$.id')), []) FROM "Initial Population" WHERE "Initial Population".patient_id = p.patient_id AND "Initial Population".resource IS NOT NULL) AS "Initial Population", (SELECT COALESCE(LIST(json_extract_string("Denominator".resource, '$.resourceType') || '/' || json_extract_string("Denominator".resource, '$.id')), []) FROM "Denominator" WHERE "Denominator".patient_id = p.patient_id AND "Denominator".resource IS NOT NULL) AS Denominator, (SELECT COALESCE(LIST(json_extract_string("Denominator Exclusions".resource, '$.resourceType') || '/' || json_extract_string("Denominator Exclusions".resource, '$.id')), []) FROM "Denominator Exclusions" WHERE "Denominator Exclusions".patient_id = p.patient_id AND "Denominator Exclusions".resource IS NOT NULL) AS "Denominator Exclusions", (SELECT COALESCE(LIST(json_extract_string("Denominator Exceptions".resource, '$.resourceType') || '/' || json_extract_string("Denominator Exceptions".resource, '$.id')), []) FROM "Denominator Exceptions" WHERE "Denominator Exceptions".patient_id = p.patient_id AND "Denominator Exceptions".resource IS NOT NULL) AS "Denominator Exceptions", (SELECT COALESCE(LIST(json_extract_string("Numerator".resource, '$.resourceType') || '/' || json_extract_string("Numerator".resource, '$.id')), []) FROM "Numerator" WHERE "Numerator".patient_id = p.patient_id AND "Numerator".resource IS NOT NULL) AS Numerator FROM _patients p ORDER BY p.patient_id ASC
